sections.Remove Assignments to Parameters:
Problem Some value is assigned to a parameter inside method’s body. Solution Use a local variable instead of a parameter. Before int discount(int inputVal, int quantity) {
  if (quantity > 50) {
    inputVal -= 2;
  }
  // ...
} After int discount(int inputVal, int quantity) {
  int result = inputVal;
  if (quantity > 50) {
    result -= 2;
  }
  // ...
} Before int Discount(int inputVal, int quantity) 
{
  if (quantity > 50) 
  {
    inputVal -= 2;
  }
  // ...
} After int Discount(int inputVal, int quantity) 
{
  int result = inputVal;

  if (quantity > 50) 
  {
    result -= 2;
  }
  // ...
} Before function discount($inputVal, $quantity) {
  if ($quantity > 50) {
    $inputVal -= 2;
  }
  ... After function discount($inputVal, $quantity) {
  $result = $inputVal;
  if ($quantity > 50) {
    $result -= 2;
  }
  ... Before def discount(inputVal, quantity):
    if quantity > 50:
        inputVal -= 2
    # ... After def discount(inputVal, quantity):
    result = inputVal
    if quantity > 50:
        result -= 2
    # ... Before discount(inputVal: number, quantity: number): number {
  if (quantity > 50) {
    inputVal -= 2;
  }
  // ...
} After discount(inputVal: number, quantity: number): number {
  let result = inputVal;
  if (quantity > 50) {
    result -= 2;
  }
  // ...
}

