sections.Self Encapsulate Field:
Self-encapsulation is distinct from ordinary Encapsulate Field : the refactoring technique given here is performed on a private field. Problem You use direct access to private fields inside a class. Solution Create a getter and setter for the field, and use only them for accessing the field. Before class Range {
  private int low, high;
  boolean includes(int arg) {
    return arg >= low && arg <= high;
  }
} After class Range {
  private int low, high;
  boolean includes(int arg) {
    return arg >= getLow() && arg <= getHigh();
  }
  int getLow() {
    return low;
  }
  int getHigh() {
    return high;
  }
} Before class Range 
{
  private int low, high;

  bool Includes(int arg) 
  {
    return arg >= low && arg <= high;
  }
} After class Range 
{
  private int low, high;

  int Low {
    get { return low; }
  }
  int High {
    get { return high; }
  }

  bool Includes(int arg) 
  {
    return arg >= Low && arg <= High;
  }
} Before private $low;
private $high;

function includes($arg) {
  return $arg >= $this->low && $arg <= $this->high;
} After private $low;
private $high;

function includes($arg) {
  return $arg >= $this->getLow() && $arg <= $this->getHigh();
}
function getLow() {
  return $this->low;
}
function getHigh() {
  return $this->high;
} Before class Range {
  private low: number
  private high: number;
  includes(arg: number): boolean {
    return arg >= low && arg <= high;
  }
} After class Range {
  private low: number
  private high: number;
  includes(arg: number): boolean {
    return arg >= getLow() && arg <= getHigh();
  }
  getLow(): number {
    return low;
  }
  getHigh(): number {
    return high;
  }
}

